VALUES
  ('social-worker-moex-02531', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '管理學者賀伯賽門（Herbert Simon）認為決策者常因為記憶、能力、時間等限制，而僅能運用直覺或習慣 迅速決策，此種現象最適合稱為下列何者？', '["垃圾桶理論（garbage can theory）", "混亂理論（chaos theory）", "有限理性（bounded rationality）", "習慣理論（habit theory）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "7528bca53179", "answer_pdf_sha1": "6a2111ca5bab", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02532', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在社會工作決策所使用的方法或技術之中，「得爾菲技術法（Delphi technique）」與「名義團體法（nominal group technique, NGT）」兩者有無不同？最適合的描述是：', '["兩者相同，只是時代不同，所以名稱不同", "兩者相同，得爾菲法是由得爾菲所倡導，而名義團體法其實是得爾菲法的實際內容", "兩者不同，名義團體法需要參與的人數遠大於得爾菲法", "兩者不同，得爾菲法參與的成員彼此無須碰面，而名義團體法允許成員聚在一起討論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "7528bca53179", "answer_pdf_sha1": "6a2111ca5bab", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02533', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '關於人力資源管理（human resource management）與人事管理（personnel management）兩者的描述， 下列那一項最正確？', '["人事管理重視人事運用的彈性；人力資源管理重視人力控制", "人事管理是工作取向，強調人事功能的發揮；人力資源管理是策略取向，強調人力管理與整體組織的 配合", "人事管理以成員為主，強調成員在組織內如何發揮潛能；人力資源管理以組織為主，強調成員如何完 成組織的目標", "人事管理由員工組成招募小組，以甄選新進員工；人力資源管理由少數主管人員負責員工招募，比較 有效率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "7528bca53179", "answer_pdf_sha1": "6a2111ca5bab", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02534', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '一般員工培訓目的可分為四個層次，如果多數學員在訓練課程結束之後，對於講師的教學方式及口語表 達技巧，感到非常喜愛和滿意，顯示已達成那一層次的培訓目的？', '["情緒層次", "反應層次", "行為層次", "學習層次"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "7528bca53179", "answer_pdf_sha1": "6a2111ca5bab", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02535', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '司徒達賢撰寫《非營利組織的經營管理》，提出一套簡易的管理邏輯思考，稱之為CORPS模式，各英文 字母所代表的意義為下列何者？', '["Client, Operation, Resources, Purpose, Service", "Client, Operation, Resources, Process, Service", "Client, Operation, Resources, Participant, Service", "Client, Operation, Resources, Promotion, Service"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "7528bca53179", "answer_pdf_sha1": "6a2111ca5bab", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02536', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '民國103年6月18日志願服務法修正之後從事災害防救的志工，其服務年資滿3年，服務時數滿300小時 以上者，憑志願服務榮譽卡進入收費之公立風景區，可享有下列何種優待措施？', '["不符合志願服務法的規定，無法申請志願服務榮譽卡及享受優待", "可申請志願服務榮譽卡，但須目的事業主管機關另出具證明，方可享受優待", "可申請志願服務榮譽卡，與社會福利機構的志工享受同等免費優待", "可申請志願服務榮譽卡，但僅能享受半價優待"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "7528bca53179", "answer_pdf_sha1": "6a2111ca5bab", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02537', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '依志願服務法第22條規定，志工依志願服務運用單位之指示進行志願服務時，因故意或過失不法侵害他 人權利者，由下列何者負損害賠償責任最為正確？', '["由志願服務運用單位負損害賠償責任", "由志工本人負損害賠償責任", "由志願服務運用單位負損害賠償責任，但志工有故意或重大過失時，運用單位對志工有求償權", "由於志工沒有報酬，志工與志願服務運用單位均不負損害賠償責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "7528bca53179", "answer_pdf_sha1": "6a2111ca5bab", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02538', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '根據Tschirhart & Bielefeld（2012）對「社會服務方案的邏輯模式」之描述，下列何者正確？', '["問題—需求—分析—方案—解決", "輸入—活動—輸出—成果—影響", "需求—問題—分析—方案—解決", "環境—組織—需求—方案—解決"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "7528bca53179", "answer_pdf_sha1": "6a2111ca5bab", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02539', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列關於「服務品質」的描述，何者錯誤？', '["全面品管（TQM）由商業組織發展而來，而社會福利機構有強烈的非營利性質，不適合引介TQM", "ISO9000是對於服務品質外部認證的一種制度", "平衡計分法（BSC）也是一種服務品質的模型", "社會福利機構的服務品質通常包括多元層面，需要多層級或多層面的衡量"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "7528bca53179", "answer_pdf_sha1": "6a2111ca5bab", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02540', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '被譽為「現代行銷學之父」，對社會行銷也很有貢獻，是下列何者？', '["麥可波特（Michael Proter）", "亨利明茲伯格（Henry Mintzberg）", "菲利普科特勒（Philip Kotler）", "理查史考特（Richard Scott）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "7528bca53179", "answer_pdf_sha1": "6a2111ca5bab", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
